#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int A[1000];
        for(int i=0;i<N;++i) scanf("%d",&A[i]);
        static int rightCnt[60001];
        memset(rightCnt,0,sizeof(rightCnt));
        for(int i=0;i<N;++i) rightCnt[A[i]]++;
        long long ans=0;
        for(int j=0;j<N;++j){
            rightCnt[A[j]]--; // remove Aj from right side
            for(int i=0;i<j;++i){
                int need = 2*A[j] - A[i];
                if(need>=1 && need<=30000) ans += rightCnt[need];
            }
        }
        printf("%lld\n",ans);
    }
    return 0;
}

